import React, { useState, useEffect } from 'react'
import { useNavigate } from '@tanstack/react-router'
import { api } from '@/lib/api'
import { Card } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'

interface Charity {
  id: string
  name: string
  description: string
  image_url: string
  impact_area: string
  region: string
  is_featured: boolean
  is_spotlight: boolean
}

const CharitiesPage: React.FC = () => {
  const navigate = useNavigate()
  const [charities, setCharities] = useState<Charity[]>([])
  const [search, setSearch] = useState('')
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    loadCharities()
  }, [search])

  const loadCharities = async () => {
    setLoading(true)
    try {
      const res = await api.getCharities(search || undefined)
      setCharities(res.data.data || [])
    } catch (error) {
      console.error('Failed to load charities:', error)
    } finally {
      setLoading(false)
    }
  }

  const featured = charities.filter((c) => c.is_featured)
  const spotlight = charities.filter((c) => c.is_spotlight)
  const others = charities.filter((c) => !c.is_featured && !c.is_spotlight)

  return (
    <div className="container mx-auto px-4 py-12">
      <div className="mb-8">
        <h1 className="text-4xl font-bold mb-2">Featured Charities</h1>
        <p className="text-muted-foreground mb-6">
          Support causes you believe in. A portion of every subscription goes to your chosen charity.
        </p>

        <Input
          type="text"
          placeholder="Search charities..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="max-w-md"
        />
      </div>

      {loading ? (
        <p className="text-muted-foreground">Loading charities...</p>
      ) : (
        <>
          {/* Spotlight Section */}
          {spotlight.length > 0 && (
            <div className="mb-12">
              <h2 className="text-2xl font-bold mb-6 text-primary">Spotlight</h2>
              <div className="grid md:grid-cols-2 gap-6">
                {spotlight.map((charity) => (
                  <Card
                    key={charity.id}
                    className="overflow-hidden hover:shadow-lg transition-shadow cursor-pointer"
                    onClick={() => navigate({ to: `/charities/${charity.id}` })}
                  >
                    <img
                      src={charity.image_url}
                      alt={charity.name}
                      className="w-full h-48 object-cover"
                    />
                    <div className="p-6">
                      <h3 className="text-xl font-semibold mb-2">{charity.name}</h3>
                      <p className="text-sm text-muted-foreground mb-4 line-clamp-2">
                        {charity.description}
                      </p>
                      <div className="flex gap-2 mb-4">
                        <span className="text-xs bg-primary/10 text-primary px-2 py-1 rounded">
                          {charity.impact_area}
                        </span>
                        <span className="text-xs bg-muted px-2 py-1 rounded">{charity.region}</span>
                      </div>
                      <Button className="w-full">Learn More</Button>
                    </div>
                  </Card>
                ))}
              </div>
            </div>
          )}

          {/* Featured Section */}
          {featured.length > 0 && (
            <div className="mb-12">
              <h2 className="text-2xl font-bold mb-6">Featured</h2>
              <div className="grid md:grid-cols-3 gap-6">
                {featured.map((charity) => (
                  <Card
                    key={charity.id}
                    className="overflow-hidden hover:shadow-lg transition-shadow cursor-pointer"
                    onClick={() => navigate({ to: `/charities/${charity.id}` })}
                  >
                    <img
                      src={charity.image_url}
                      alt={charity.name}
                      className="w-full h-40 object-cover"
                    />
                    <div className="p-4">
                      <h3 className="font-semibold mb-2">{charity.name}</h3>
                      <p className="text-xs text-muted-foreground mb-3 line-clamp-2">
                        {charity.description}
                      </p>
                      <div className="flex gap-1 mb-3">
                        <span className="text-xs bg-muted px-2 py-0.5 rounded">
                          {charity.impact_area}
                        </span>
                        <span className="text-xs bg-muted px-2 py-0.5 rounded">{charity.region}</span>
                      </div>
                      <Button size="sm" className="w-full">
                        Learn More
                      </Button>
                    </div>
                  </Card>
                ))}
              </div>
            </div>
          )}

          {/* All Charities */}
          {others.length > 0 && (
            <div>
              <h2 className="text-2xl font-bold mb-6">All Charities</h2>
              <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                {others.map((charity) => (
                  <Card
                    key={charity.id}
                    className="overflow-hidden hover:shadow-lg transition-shadow cursor-pointer"
                    onClick={() => navigate({ to: `/charities/${charity.id}` })}
                  >
                    <img
                      src={charity.image_url}
                      alt={charity.name}
                      className="w-full h-40 object-cover"
                    />
                    <div className="p-4">
                      <h3 className="font-semibold mb-2 line-clamp-1">{charity.name}</h3>
                      <p className="text-xs text-muted-foreground mb-3 line-clamp-2">
                        {charity.description}
                      </p>
                      <div className="flex gap-1 mb-3">
                        <span className="text-xs bg-muted px-2 py-0.5 rounded">
                          {charity.impact_area}
                        </span>
                        <span className="text-xs bg-muted px-2 py-0.5 rounded">{charity.region}</span>
                      </div>
                      <Button size="sm" variant="outline" className="w-full">
                        Learn More
                      </Button>
                    </div>
                  </Card>
                ))}
              </div>
            </div>
          )}

          {charities.length === 0 && (
            <Card className="p-12 text-center">
              <p className="text-muted-foreground">No charities found matching your search</p>
            </Card>
          )}
        </>
      )}
    </div>
  )
}

export default CharitiesPage
