import React, { useState, useEffect } from 'react'
import { api } from '@/lib/api'
import { Card } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'

interface Winner {
  id: string
  draw_id: string
  tier: number
  matched_numbers: number[]
  prize_amount: number
  verification_status: string
  payment_status: string
  verified_at?: string
  paid_at?: string
  draw_month: string
  proof_image_url?: string
}

const WinningsPage: React.FC = () => {
  const [winners, setWinners] = useState<Winner[]>([])
  const [loading, setLoading] = useState(true)
  const [expandedId, setExpandedId] = useState<string | null>(null)

  useEffect(() => {
    loadWinnings()
  }, [])

  const loadWinnings = async () => {
    setLoading(true)
    try {
      const res = await api.getUserWinners()
      setWinners(res.data.data || [])
    } catch (error) {
      console.error('Failed to load winnings:', error)
    } finally {
      setLoading(false)
    }
  }

  const getTierLabel = (tier: number) => {
    switch (tier) {
      case 5:
        return '5-Number Match'
      case 4:
        return '4-Number Match'
      case 3:
        return '3-Number Match'
      default:
        return 'Prize'
    }
  }

  const getVerificationBadgeVariant = (status: string) => {
    switch (status) {
      case 'verified':
        return 'default'
      case 'rejected':
        return 'destructive'
      case 'pending':
        return 'secondary'
      default:
        return 'outline'
    }
  }

  const getPaymentBadgeVariant = (status: string) => {
    return status === 'paid' ? 'default' : 'secondary'
  }

  const totalWinnings = winners.reduce((sum, w) => sum + w.prize_amount, 0)
  const totalVerified = winners.filter((w) => w.verification_status === 'verified').length
  const totalPaid = winners.filter((w) => w.payment_status === 'paid').length

  return (
    <div className="container mx-auto px-4 py-12">
      <h1 className="text-4xl font-bold mb-2">Your Winnings</h1>
      <p className="text-muted-foreground mb-8">Track your lottery winnings and verification status</p>

      {/* Summary Cards */}
      <div className="grid md:grid-cols-3 gap-6 mb-8">
        <Card className="p-6">
          <p className="text-sm text-muted-foreground mb-1">Total Winnings</p>
          <p className="text-3xl font-bold text-primary">${totalWinnings.toFixed(2)}</p>
        </Card>
        <Card className="p-6">
          <p className="text-sm text-muted-foreground mb-1">Verified</p>
          <p className="text-3xl font-bold">{totalVerified}</p>
          <p className="text-xs text-muted-foreground">of {winners.length} prizes</p>
        </Card>
        <Card className="p-6">
          <p className="text-sm text-muted-foreground mb-1">Paid Out</p>
          <p className="text-3xl font-bold text-green-600">${winners
            .filter((w) => w.payment_status === 'paid')
            .reduce((sum, w) => sum + w.prize_amount, 0)
            .toFixed(2)}</p>
        </Card>
      </div>

      {/* Winnings List */}
      {loading ? (
        <p className="text-muted-foreground">Loading winnings...</p>
      ) : winners.length === 0 ? (
        <Card className="p-12 text-center">
          <p className="text-muted-foreground mb-4">No winnings yet</p>
          <p className="text-sm text-muted-foreground">
            Keep entering monthly draws to win prizes!
          </p>
        </Card>
      ) : (
        <div className="space-y-4">
          {winners.map((winner) => (
            <Card key={winner.id} className="p-6">
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="text-xl font-semibold">{getTierLabel(winner.tier)}</h3>
                    <Badge variant={getVerificationBadgeVariant(winner.verification_status)}>
                      {winner.verification_status}
                    </Badge>
                    <Badge variant={getPaymentBadgeVariant(winner.payment_status)}>
                      {winner.payment_status}
                    </Badge>
                  </div>

                  <div className="grid md:grid-cols-4 gap-4 mb-4">
                    <div>
                      <p className="text-xs text-muted-foreground">Prize Amount</p>
                      <p className="text-lg font-bold">${winner.prize_amount.toFixed(2)}</p>
                    </div>
                    <div>
                      <p className="text-xs text-muted-foreground">Draw Month</p>
                      <p className="font-semibold">
                        {new Date(winner.draw_month).toLocaleDateString('en-US', {
                          year: 'numeric',
                          month: 'long',
                        })}
                      </p>
                    </div>
                    <div>
                      <p className="text-xs text-muted-foreground">Matched Numbers</p>
                      <p className="font-semibold">
                        {Array.isArray(winner.matched_numbers)
                          ? winner.matched_numbers.join(', ')
                          : 'N/A'}
                      </p>
                    </div>
                    {winner.verified_at && (
                      <div>
                        <p className="text-xs text-muted-foreground">Verified</p>
                        <p className="text-sm">
                          {new Date(winner.verified_at).toLocaleDateString()}
                        </p>
                      </div>
                    )}
                  </div>

                  {winner.verification_status === 'pending' && !winner.proof_image_url && (
                    <p className="text-sm text-orange-600 bg-orange-50 p-3 rounded mb-4">
                      Please submit proof of your winning score to verify this prize.
                    </p>
                  )}
                </div>

                {expandedId !== winner.id && (
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setExpandedId(winner.id)}
                  >
                    Details
                  </Button>
                )}
              </div>

              {expandedId === winner.id && (
                <div className="border-t pt-4 mt-4">
                  <p className="text-sm text-muted-foreground mb-2">Prize Status Timeline:</p>
                  <div className="space-y-2 text-sm">
                    <p>
                      <span className="font-semibold">Won:</span>{' '}
                      {new Date(winner.draw_month).toLocaleDateString()}
                    </p>
                    {winner.verified_at && (
                      <p>
                        <span className="font-semibold">Verified:</span>{' '}
                        {new Date(winner.verified_at).toLocaleDateString()}
                      </p>
                    )}
                    {winner.paid_at && (
                      <p>
                        <span className="font-semibold">Paid:</span>{' '}
                        {new Date(winner.paid_at).toLocaleDateString()}
                      </p>
                    )}
                  </div>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setExpandedId(null)}
                    className="mt-4"
                  >
                    Collapse
                  </Button>
                </div>
              )}
            </Card>
          ))}
        </div>
      )}
    </div>
  )
}

export default WinningsPage
