import React, { useState, useEffect } from 'react'
import { useNavigate } from '@tanstack/react-router'
import { api } from '@/lib/api'
import { Card } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Slider } from '@/components/ui/slider'

interface Charity {
  id: string
  name: string
  description: string
  image_url: string
  impact_area: string
  region: string
}

interface UserCharity {
  charity_id: string
  contribution_percentage: number
  name: string
  image_url: string
}

const CharitySelectionPage: React.FC = () => {
  const navigate = useNavigate()
  const [charities, setCharities] = useState<Charity[]>([])
  const [selected, setSelected] = useState<Charity | null>(null)
  const [percentage, setPercentage] = useState(10)
  const [userCharity, setUserCharity] = useState<UserCharity | null>(null)
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)

  useEffect(() => {
    loadCharities()
    loadUserCharity()
  }, [])

  const loadCharities = async () => {
    try {
      const res = await api.getCharities()
      setCharities(res.data.data || [])
      if (res.data.data && res.data.data.length > 0) {
        setSelected(res.data.data[0])
      }
    } catch (error) {
      console.error('Failed to load charities:', error)
    } finally {
      setLoading(false)
    }
  }

  const loadUserCharity = async () => {
    try {
      const res = await api.getUserCharitySelection()
      if (res.data.data) {
        setUserCharity(res.data.data)
        setPercentage(res.data.data.contribution_percentage)
      }
    } catch (error) {
      console.error('Failed to load user charity:', error)
    }
  }

  const handleSave = async () => {
    if (!selected) return

    setSaving(true)
    try {
      await api.selectCharity(selected.id, percentage)
      setUserCharity({
        charity_id: selected.id,
        contribution_percentage: percentage,
        name: selected.name,
        image_url: selected.image_url,
      })
      alert('Charity selection saved!')
    } catch (error) {
      console.error('Failed to save charity selection:', error)
      alert('Failed to save charity selection')
    } finally {
      setSaving(false)
    }
  }

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-12">
        <p className="text-muted-foreground">Loading charities...</p>
      </div>
    )
  }

  return (
    <div className="container mx-auto px-4 py-12">
      <div className="max-w-4xl mx-auto">
        <h1 className="text-4xl font-bold mb-2">Choose Your Charity</h1>
        <p className="text-muted-foreground mb-8">
          Select a charity to support with your subscription
        </p>

        {/* Current Selection */}
        {userCharity && (
          <Card className="p-6 mb-8 bg-green-50 border-green-200">
            <p className="text-sm text-green-600 font-semibold mb-2">CURRENT SELECTION</p>
            <div className="flex items-center gap-4">
              <img
                src={userCharity.image_url}
                alt={userCharity.name}
                className="w-12 h-12 rounded object-cover"
              />
              <div className="flex-1">
                <p className="font-semibold">{userCharity.name}</p>
                <p className="text-sm text-muted-foreground">
                  {userCharity.contribution_percentage}% of your subscription
                </p>
              </div>
            </div>
          </Card>
        )}

        {/* Charity Grid */}
        <div className="grid md:grid-cols-2 gap-4 mb-8">
          {charities.map((charity) => (
            <Card
              key={charity.id}
              className={`p-4 cursor-pointer transition-all ${
                selected?.id === charity.id ? 'ring-2 ring-primary' : ''
              }`}
              onClick={() => setSelected(charity)}
            >
              <img
                src={charity.image_url}
                alt={charity.name}
                className="w-full h-40 rounded object-cover mb-3"
              />
              <h3 className="font-semibold mb-1">{charity.name}</h3>
              <p className="text-xs text-muted-foreground mb-2 line-clamp-2">
                {charity.description}
              </p>
              <div className="flex gap-2 text-xs">
                <span className="bg-muted px-2 py-1 rounded">{charity.impact_area}</span>
                <span className="bg-muted px-2 py-1 rounded">{charity.region}</span>
              </div>
            </Card>
          ))}
        </div>

        {/* Contribution Percentage */}
        {selected && (
          <Card className="p-6 mb-8">
            <h3 className="text-xl font-semibold mb-4">Contribution Percentage</h3>
            <div className="space-y-4">
              <div>
                <p className="text-2xl font-bold text-primary">{percentage}%</p>
                <p className="text-sm text-muted-foreground">
                  of your subscription goes to {selected.name}
                </p>
              </div>

              <Slider
                value={[percentage]}
                onValueChange={(value) => setPercentage(value[0])}
                min={10}
                max={100}
                step={5}
                className="w-full"
              />

              <div className="text-xs text-muted-foreground space-y-1">
                <p>Minimum contribution: 10% (required)</p>
                <p>Maximum contribution: 100% (optional)</p>
                {percentage > 10 && (
                  <p className="text-green-600 font-semibold">
                    Thank you for giving {percentage - 10}% extra!
                  </p>
                )}
              </div>
            </div>
          </Card>
        )}

        {/* Actions */}
        <div className="flex gap-4">
          <Button size="lg" onClick={handleSave} disabled={saving || !selected}>
            {saving ? 'Saving...' : 'Save Selection'}
          </Button>
          <Button size="lg" variant="outline" onClick={() => navigate({ to: '/dashboard' })}>
            Back to Dashboard
          </Button>
        </div>
      </div>
    </div>
  )
}

export default CharitySelectionPage
