import React, { useState, useEffect } from 'react'
import { Card } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'

interface Winner {
  id: string
  user_id: string
  full_name: string
  email: string
  tier: number
  matched_numbers: number[]
  prize_amount: number
  verification_status: string
  payment_status: string
  verified_at?: string
  paid_at?: string
  draw_month: string
  proof_image_url?: string
}

const WinnersPage: React.FC = () => {
  const [winners, setWinners] = useState<Winner[]>([])
  const [filter, setFilter] = useState<'all' | 'pending' | 'verified' | 'rejected'>('all')
  const [loading, setLoading] = useState(true)
  const [verifying, setVerifying] = useState<string | null>(null)

  useEffect(() => {
    loadWinners()
  }, [filter])

  const loadWinners = async () => {
    setLoading(true)
    try {
      // Direct fetch since we haven't created the admin winners method
      const params = new URLSearchParams()
      if (filter !== 'all') params.append('status', filter)

      const res = await fetch(`/api/winners/admin?${params}`, {
        headers: {
          Authorization: `Bearer ${localStorage.getItem('authToken')}`,
        },
      })

      const data = await res.json()
      setWinners(data)
    } catch (error) {
      console.error('Failed to load winners:', error)
    } finally {
      setLoading(false)
    }
  }

  const handleVerifyWinner = async (winnerId: string, verified: boolean) => {
    setVerifying(winnerId)
    try {
      const res = await fetch(`/api/winners/${winnerId}/verify`, {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${localStorage.getItem('authToken')}`,
        },
        body: JSON.stringify({ verified }),
      })

      if (!res.ok) throw new Error('Failed to verify winner')

      loadWinners()
      alert(`Winner ${verified ? 'verified' : 'rejected'} successfully!`)
    } catch (error) {
      console.error('Failed to verify winner:', error)
      alert('Failed to update winner status')
    } finally {
      setVerifying(null)
    }
  }

  const handleMarkPaid = async (winnerId: string) => {
    setVerifying(winnerId)
    try {
      const res = await fetch(`/api/winners/${winnerId}/payout`, {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${localStorage.getItem('authToken')}`,
        },
        body: JSON.stringify({}),
      })

      if (!res.ok) throw new Error('Failed to mark as paid')

      loadWinners()
      alert('Marked as paid successfully!')
    } catch (error) {
      console.error('Failed to mark as paid:', error)
      alert('Failed to mark as paid')
    } finally {
      setVerifying(null)
    }
  }

  const pendingCount = winners.filter((w) => w.verification_status === 'pending').length
  const totalPool = winners.reduce((sum, w) => sum + w.prize_amount, 0)
  const paidTotal = winners
    .filter((w) => w.payment_status === 'paid')
    .reduce((sum, w) => sum + w.prize_amount, 0)

  return (
    <div className="container mx-auto px-4 py-12">
      <h1 className="text-4xl font-bold mb-2">Winners Management</h1>
      <p className="text-muted-foreground mb-8">Verify winners and manage payouts</p>

      {/* Summary Stats */}
      <div className="grid md:grid-cols-4 gap-6 mb-8">
        <Card className="p-6">
          <p className="text-sm text-muted-foreground mb-1">Pending Verification</p>
          <p className="text-3xl font-bold text-orange-600">{pendingCount}</p>
        </Card>
        <Card className="p-6">
          <p className="text-sm text-muted-foreground mb-1">Total Prize Pool</p>
          <p className="text-3xl font-bold">${totalPool.toFixed(2)}</p>
        </Card>
        <Card className="p-6">
          <p className="text-sm text-muted-foreground mb-1">Paid Out</p>
          <p className="text-3xl font-bold text-green-600">${paidTotal.toFixed(2)}</p>
        </Card>
        <Card className="p-6">
          <p className="text-sm text-muted-foreground mb-1">Remaining</p>
          <p className="text-3xl font-bold">${(totalPool - paidTotal).toFixed(2)}</p>
        </Card>
      </div>

      {/* Filter Tabs */}
      <div className="flex gap-2 mb-6">
        {(['all', 'pending', 'verified', 'rejected'] as const).map((f) => (
          <Button
            key={f}
            variant={filter === f ? 'default' : 'outline'}
            onClick={() => setFilter(f)}
            className="capitalize"
          >
            {f === 'all' ? 'All Winners' : f}
          </Button>
        ))}
      </div>

      {/* Winners List */}
      {loading ? (
        <p className="text-muted-foreground">Loading winners...</p>
      ) : winners.length === 0 ? (
        <Card className="p-12 text-center">
          <p className="text-muted-foreground">No winners to display</p>
        </Card>
      ) : (
        <div className="space-y-3">
          {winners.map((winner) => (
            <Card key={winner.id} className="p-4">
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="font-semibold">{winner.full_name}</h3>
                    <Badge
                      variant={
                        winner.verification_status === 'verified'
                          ? 'default'
                          : winner.verification_status === 'rejected'
                            ? 'destructive'
                            : 'secondary'
                      }
                    >
                      {winner.verification_status}
                    </Badge>
                    <Badge
                      variant={winner.payment_status === 'paid' ? 'default' : 'secondary'}
                    >
                      {winner.payment_status}
                    </Badge>
                  </div>

                  <div className="grid md:grid-cols-5 gap-4 text-sm">
                    <div>
                      <p className="text-xs text-muted-foreground">Email</p>
                      <p className="font-mono">{winner.email}</p>
                    </div>
                    <div>
                      <p className="text-xs text-muted-foreground">Prize Tier</p>
                      <p className="font-semibold">{winner.tier}-Number Match</p>
                    </div>
                    <div>
                      <p className="text-xs text-muted-foreground">Amount</p>
                      <p className="font-semibold">${winner.prize_amount.toFixed(2)}</p>
                    </div>
                    <div>
                      <p className="text-xs text-muted-foreground">Matched Numbers</p>
                      <p className="font-semibold">
                        {Array.isArray(winner.matched_numbers) ? winner.matched_numbers.join(', ') : 'N/A'}
                      </p>
                    </div>
                    <div>
                      <p className="text-xs text-muted-foreground">Draw Month</p>
                      <p className="font-semibold">
                        {new Date(winner.draw_month).toLocaleDateString('en-US', {
                          month: 'short',
                          year: 'numeric',
                        })}
                      </p>
                    </div>
                  </div>
                </div>

                {/* Actions */}
                <div className="flex flex-col gap-2">
                  {winner.verification_status === 'pending' && (
                    <>
                      <Button
                        size="sm"
                        onClick={() => handleVerifyWinner(winner.id, true)}
                        disabled={verifying === winner.id}
                        className="bg-green-600 hover:bg-green-700"
                      >
                        Verify
                      </Button>
                      <Button
                        size="sm"
                        variant="destructive"
                        onClick={() => handleVerifyWinner(winner.id, false)}
                        disabled={verifying === winner.id}
                      >
                        Reject
                      </Button>
                    </>
                  )}

                  {winner.verification_status === 'verified' && winner.payment_status === 'pending' && (
                    <Button
                      size="sm"
                      onClick={() => handleMarkPaid(winner.id)}
                      disabled={verifying === winner.id}
                      className="bg-blue-600 hover:bg-blue-700"
                    >
                      Mark Paid
                    </Button>
                  )}

                  {winner.proof_image_url && winner.verification_status !== 'verified' && (
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => window.open(winner.proof_image_url, '_blank')}
                    >
                      View Proof
                    </Button>
                  )}
                </div>
              </div>
            </Card>
          ))}
        </div>
      )}
    </div>
  )
}

export default WinnersPage
