import React, { useState, useEffect } from 'react'
import { api } from '@/lib/api'
import { Card } from '@/components/ui/card'
import { Button } from '@/components/ui/button'

interface SimulatedDraw {
  drawId: string
  drawNumbers: number[]
  totalParticipants: number
  totalPool: number
  winners: any[]
  prizes: any
}

const DrawManagementPage: React.FC = () => {
  const [currentDraw, setCurrentDraw] = useState<any>(null)
  const [drawHistory, setDrawHistory] = useState<any[]>([])
  const [simulated, setSimulated] = useState<SimulatedDraw | null>(null)
  const [loading, setLoading] = useState(true)
  const [publishing, setPublishing] = useState(false)

  useEffect(() => {
    loadDraws()
  }, [])

  const loadDraws = async () => {
    setLoading(true)
    try {
      const [currentRes, historyRes] = await Promise.all([
        api.getCurrentDraw(),
        // Using direct fetch since we haven't created the getDrawHistory method
        fetch('/api/draws/history'),
      ])

      setCurrentDraw(currentRes.data.data)

      const historyData = await historyRes.json()
      setDrawHistory(historyData)
    } catch (error) {
      console.error('Failed to load draws:', error)
    } finally {
      setLoading(false)
    }
  }

  const handleSimulateDraw = async () => {
    setLoading(true)
    try {
      const res = await api.simulateDraw()
      setSimulated(res.data.data)
    } catch (error) {
      console.error('Failed to simulate draw:', error)
      alert('Failed to simulate draw')
    } finally {
      setLoading(false)
    }
  }

  const handlePublishDraw = async () => {
    if (!simulated) return

    setPublishing(true)
    try {
      // Use direct fetch for publishing
      const res = await fetch('/api/draws/publish', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${localStorage.getItem('authToken')}`,
        },
        body: JSON.stringify({
          drawNumbers: simulated.drawNumbers,
          winners: simulated.winners,
        }),
      })

      if (!res.ok) {
        throw new Error('Failed to publish draw')
      }

      alert('Draw published successfully!')
      setSimulated(null)
      loadDraws()
    } catch (error) {
      console.error('Failed to publish draw:', error)
      alert('Failed to publish draw')
    } finally {
      setPublishing(false)
    }
  }

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-12">
        <p className="text-muted-foreground">Loading draws...</p>
      </div>
    )
  }

  return (
    <div className="container mx-auto px-4 py-12">
      <h1 className="text-4xl font-bold mb-8">Draw Management</h1>

      {/* Current Draw */}
      {currentDraw && (
        <Card className="p-6 mb-8">
          <h2 className="text-2xl font-semibold mb-4">Current Month Draw</h2>
          <div className="grid md:grid-cols-3 gap-6 mb-6">
            <div>
              <p className="text-sm text-muted-foreground">Draw Month</p>
              <p className="text-lg font-semibold">
                {new Date(currentDraw.draw_month).toLocaleDateString('en-US', {
                  year: 'numeric',
                  month: 'long',
                })}
              </p>
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Status</p>
              <p className="text-lg font-semibold capitalize">{currentDraw.status}</p>
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Numbers</p>
              <p className="text-lg font-semibold">
                {currentDraw.draw_numbers ? currentDraw.draw_numbers.join(', ') : 'Not drawn'}
              </p>
            </div>
          </div>

          <Button onClick={handleSimulateDraw} disabled={loading || !!simulated}>
            Simulate Draw
          </Button>
        </Card>
      )}

      {/* Simulated Results */}
      {simulated && (
        <Card className="p-6 mb-8 border-blue-200 bg-blue-50">
          <h2 className="text-2xl font-semibold mb-4">Draw Simulation Results</h2>

          <div className="grid md:grid-cols-4 gap-6 mb-6">
            <div>
              <p className="text-sm text-muted-foreground">Draw Numbers</p>
              <p className="text-lg font-semibold">{simulated.drawNumbers.join(', ')}</p>
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Participants</p>
              <p className="text-lg font-semibold">{simulated.totalParticipants}</p>
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Total Prize Pool</p>
              <p className="text-lg font-semibold">${simulated.totalPool.toFixed(2)}</p>
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Total Winners</p>
              <p className="text-lg font-semibold">{simulated.winners.length}</p>
            </div>
          </div>

          <div className="mb-6">
            <h3 className="font-semibold mb-3">Prize Distribution</h3>
            <div className="space-y-2">
              <p>5-Number Match: ${simulated.prizes.tier5.toFixed(2)} per winner</p>
              <p>4-Number Match: ${simulated.prizes.tier4.toFixed(2)} per winner</p>
              <p>3-Number Match: ${simulated.prizes.tier3.toFixed(2)} per winner</p>
            </div>
          </div>

          <div className="flex gap-4">
            <Button
              onClick={handlePublishDraw}
              disabled={publishing}
              className="bg-green-600 hover:bg-green-700"
            >
              {publishing ? 'Publishing...' : 'Publish Draw'}
            </Button>
            <Button variant="outline" onClick={() => setSimulated(null)}>
              Cancel
            </Button>
          </div>
        </Card>
      )}

      {/* Previous Draws */}
      {drawHistory.length > 0 && (
        <div>
          <h2 className="text-2xl font-semibold mb-4">Previous Draws</h2>
          <div className="space-y-3">
            {drawHistory.map((draw) => (
              <Card key={draw.id} className="p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="font-semibold">
                      {new Date(draw.draw_month).toLocaleDateString('en-US', {
                        year: 'numeric',
                        month: 'long',
                      })}
                    </p>
                    <p className="text-sm text-muted-foreground">
                      Numbers: {draw.draw_numbers.join(', ')}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="text-sm text-muted-foreground">Prize Pool</p>
                    <p className="font-semibold">${draw.total_prize_pool.toFixed(2)}</p>
                  </div>
                </div>
              </Card>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

export default DrawManagementPage
